<?php namespace App\Services; use Illuminate\Support\Facades\Log; use Illuminate\Support\Facades\Auth; use Illuminate\Support\Facades\DB; use Illuminate\Support\Facades\Request; class LogService { public function logActivity(string $action, string $module, array $details = [], string $level = 'info'): void { $user = Auth::user(); $logData = [ 'user_id' => $user ? $user->id : null, 'action' => $action, 'module' => $module, 'ip_address' => Request::ip(), 'user_agent' => Request::userAgent(), 'details' => json_encode($details), 'created_at' => now(), ]; Log::log($level, "Activity Log: {$action}", $logData); DB::table('activity_logs')->insert($logData); } public function emergency(string $action, array $details = []): void { $this->logActivity($action, 'SYSTEM', $details, 'emergency'); } public function info(string $action, string $module, array $details = []): void { $this->logActivity($action, $module, $details, 'info'); } public function warning(string $action, string $module, array $details = []): void { $this->logActivity($action, $module, $details, 'warning'); } }